__d(function(g,r,i,a,m,e,d){"use strict";Object.defineProperty(e,'__esModule',{value:!0}),Object.defineProperty(e,"species",{enumerable:!0,get:function(){return t}});const t=[{id:'carp',name:'Common Carp',commonName:'Carp',latinName:'Cyprinus carpio',type:'coarse',habitat:'Lakes, reservoirs, slow rivers with weedy margins and silty beds',behaviour:'Bottom feeders that root through silt for food. Most active at dawn and dusk. Highly cautious and intelligent, often wary of rigs.',bestSeasons:['Spring','Summer','Autumn'],bestWeather:'Warm, overcast days with light SW wind. Pressure rising after rain.',baits:[{name:'Boilies',effectiveness:10},{name:'Sweetcorn',effectiveness:8},{name:'Bread',effectiveness:7},{name:'Tiger Nuts',effectiveness:9},{name:'Pellets',effectiveness:8}],rigs:[{name:'Hair Rig',description:'The classic carp rig - bait mounted on a hair off the hook bend'},{name:'Zig Rig',description:'For surface or mid-water fishing when carp are not feeding on bottom'},{name:'Chod Rig',description:'Self-hooking rig ideal for weedy or silty lake beds'}],hookSizes:['4','6','8'],lineWeight:'10-15lb',legalSize:38,recordWeight:68.1,averageWeight:'5-20kg',averageLength:'60-100cm',tips:['Bait up little and often to keep fish in your swim','Use PVA bags to prevent tangles and deliver bait accurately','Fish near features like lily pads, snags, and overhanging trees','Match the hatch \u2014 use natural-coloured baits in clear water','Consider night fishing in summer when carp are most active'],difficulty:'intermediate',rarity:'rare',rarityColor:'#3B82F6',rarityDescription:'Intelligent and wary. Large specimens require specialist tactics and patience.',spawnConditions:'Weedy lake margins, gravel bars, near island features',catchRate:40,emoji:'\ud83d\udc1f',bestTimes:{timeOfDay:['Dawn (5am-8am)','Dusk (7pm-10pm)','Night fishing productive in summer'],moonPhase:'Full moon and new moon periods \u2014 fish feed more actively',season:'Late spring through autumn peak. Summer nights excellent.',temperature:'Water temp 15-22\xb0C ideal. Slow below 8\xb0C.',barometric:'Stable or slowly rising pressure. Avoid sudden drops.',weather:'Warm overcast days. Light SW wind pushing into a bank.'},catchingTips:['Spod or spomb a bed of bait (boilies, pellets, corn) before fishing to draw fish in','Fish tight to features \u2014 lily pads, overhanging trees, gravel bars hold fish','Use a marker float to find gravel spots and drop-offs before casting','Match hook bait to your loose feed \u2014 if spodding pellets, fish a pellet on the hair','Check drag is set correctly \u2014 carp will bolt and snap light lines instantly','Fishing with two or three rods covering different areas increases your chances significantly','Stalk fish visually on warm days \u2014 spotted carp can be targeted precisely','Use dissolving PVA mesh bags around the lead to present a neat bait package'],commonMistakes:['Setting the drag too tight \u2014 carp bolt and the line or rod tip breaks','Fishing in the wrong spot without using a marker float first','Overfeeding in cold water \u2014 less is more when temps drop below 10\xb0C','Not checking the hook point after each cast \u2014 blunt hooks miss takes','Rushing the fight \u2014 carp near the net often have a second run in them'],proTips:['In hot summer weather, look for carp basking near the surface at midday \u2014 a floating bait (controller float and bread crust) can produce monsters other anglers ignore','Introduce bait via a rowing boat after dark to reach far-bank snags and islands \u2014 these underfished areas hold the biggest fish','Study the water in winter when levels drop \u2014 find gravel bars and depth changes that you can then fish accurately in summer']},{id:'pike',name:'Northern Pike',commonName:'Pike',latinName:'Esox lucius',type:'coarse',habitat:'Lakes, rivers, drains with abundant weed cover and prey fish',behaviour:'Ambush predator that lies motionless in weeds waiting for prey. Solitary and territorial. Most active in cold water.',bestSeasons:['Autumn','Winter'],bestWeather:'Cold, overcast days. Pike feed well in low light conditions and cold snaps.',baits:[{name:'Deadbait (Mackerel)',effectiveness:10},{name:'Deadbait (Herring)',effectiveness:9},{name:'Large Spinners',effectiveness:8},{name:'Jerkbaits',effectiveness:8},{name:'Live Perch',effectiveness:9}],rigs:[{name:'Deadbait Ledger',description:'Simple ledgered deadbait on wire trace with two treble hooks'},{name:'Popped-up Deadbait',description:'Injected with air to hover above bottom and attract attention'},{name:'Float Paternoster',description:'Livebaited rig that suspends bait at a set depth'}],hookSizes:['6 (treble)','8 (treble)'],lineWeight:'15-20lb',legalSize:45,recordWeight:21.2,averageWeight:'2-10kg',averageLength:'60-100cm',tips:['Always use a wire trace - pike teeth will cut through mono instantly','Handle with care - support their weight fully and use unhooking mat','Fish near reed beds, lily pads, and overhanging trees','Try slow wobbling deadbaits near the bottom in winter','Never hold pike vertically by the gills - causes internal damage'],difficulty:'intermediate',rarity:'epic',rarityColor:'#8B5CF6',rarityDescription:'Apex predator. Large specimens are solitary and extremely wary.',spawnConditions:'Cold water reed beds and weed margins in autumn and winter',catchRate:20,emoji:'\ud83e\uddb7',bestTimes:{timeOfDay:['Dusk (4pm-7pm)','Dawn (7am-9am) in cold weather','Midday productive in deep winter'],moonPhase:'New moon and full moon periods see increased predator activity',season:'September through February peak. Cold water triggers feeding sprees.',temperature:'Water temp 4-12\xb0C ideal. Pike slow down in warm summer water above 18\xb0C.',barometric:'Steady or falling pressure. Cold fronts often trigger feeding.',weather:'Cold, overcast days with frost overnight. Avoid sudden warm spells.'},catchingTips:['Position deadbaits so the scent trail drifts into likely ambush areas like weed margins','Wobble a deadbait slowly through the swim to imitate an injured fish \u2014 very effective in rivers','Search the water with lures first, then switch to static deadbaits for big females','In large stillwaters, fan-cast lures to cover water before settling on a deadbait swim','Use oily sea baits (mackerel, smelt) in coloured water for maximum scent trail','Set your float so the bait is just off the bottom \u2014 pike rarely look up for food'],commonMistakes:['Using monofilament instead of wire trace \u2014 a pike will bite through mono in seconds','Striking too early \u2014 wait for the pike to have moved off with the bait before setting hooks','Fishing in the same spot all day \u2014 pike are territorial, move if you get no runs after 45 minutes','Returning pike without fully reviving them \u2014 always hold upright in the water until it kicks away'],proTips:['The biggest pike in any water are almost always female and solitary \u2014 target one specific lie with a large bait and wait rather than roving','In very cold clear water, scale right down to a small roach fished under a float on 12lb wire \u2014 big pike can be finicky when the water is near freezing']},{id:'perch',name:'European Perch',commonName:'Perch',latinName:'Perca fluviatilis',type:'coarse',habitat:'Lakes, rivers, canals with structure like bridges, sunken trees, and weed',behaviour:'Shoal hunters in their early years, becoming solitary as they grow. Aggressive predators that will attack lures confidently.',bestSeasons:['Autumn','Winter','Spring'],bestWeather:'Overcast with light winds. Bright sunshine can push perch deep.',baits:[{name:'Worms',effectiveness:10},{name:'Maggots',effectiveness:9},{name:'Small Spinners',effectiveness:9},{name:'Drop Shots',effectiveness:8},{name:'Small Deadbaits',effectiveness:7}],rigs:[{name:'Drop Shot',description:'Vertical presentation that keeps bait at exact depth, perfect for perch'},{name:'Float Rig',description:'Classic float fishing with worm or maggot in likely spots'},{name:'Texas Rig',description:'Weedless soft plastic presentation through snaggy areas'}],hookSizes:['10','12','14'],lineWeight:'6-10lb',legalSize:25,recordWeight:2.78,averageWeight:'0.2-1kg',averageLength:'20-40cm',tips:['Look for perch near structure - moored boats, bridge supports, fallen trees','Drop shotting is devastatingly effective for big perch','Large perch are often loners - one big fish per spot','Perch turn on in autumn - this is peak season for specimen perch','Use lighter lines in clear water for more takes'],difficulty:'beginner',rarity:'uncommon',rarityColor:'#22C55E',rarityDescription:'Common but larger specimens require specific structure and skill to locate.',spawnConditions:'Near bridges, fallen trees, lock structures',catchRate:65,emoji:'\ud83c\udfa3',bestTimes:{timeOfDay:['Dawn (6am-9am)','Late afternoon (3pm-6pm)','Overcast midday sessions'],moonPhase:'New moon periods \u2014 perch are bolder in lower light',season:'September through January prime. Autumn produces the best specimens.',temperature:'Water temp 8-14\xb0C optimal. Good throughout autumn and winter.',barometric:'Stable or rising pressure. High pressure with clear cold days excellent.',weather:'Overcast days with no wind. Bright sunny days push them deep.'},catchingTips:['Work a drop shot vertically next to bridge supports, ladders, and moored boats','Drag a worm slowly along the bottom through dark silty areas \u2014 big perch love a natural worm','When you catch one perch, stay put \u2014 they hunt in packs and more will follow','Scale down your hook and bait in clear cold water to improve shy bite conversion','Try a small copper spinner retrieved slowly and erratically near submerged structure','Fish the shaded side of bridges and lock walls \u2014 perch always prefer to ambush from shadow'],commonMistakes:['Moving too quickly \u2014 perch need time to respond, especially in cold water','Using too heavy a line in clear water \u2014 6lb fluorocarbon is far better than 10lb mono','Not fishing deep enough \u2014 big perch drop to depth in winter, try 10ft+ in lakes'],proTips:['After finding fish on drop shot, switch to a small deadbait (roach fry or tiny smelt) for the biggest fish in the shoal \u2014 specimen perch prefer something they can really eat','On canals, walk the entire stretch and drop shot every piece of visible structure rather than sitting in one swim \u2014 roving catches far more fish']},{id:'tench',name:'Tench',commonName:'Tench',latinName:'Tinca tinca',type:'coarse',habitat:'Weedy lakes and slow rivers with muddy bottoms and dense vegetation',behaviour:'Dawn and dusk feeders that root through mud for food. Produce characteristic bubbles when feeding. Often found in dense weed beds.',bestSeasons:['Spring','Summer'],bestWeather:'Warm, calm mornings with high pressure. Tench love pre-dawn sessions.',baits:[{name:'Sweetcorn',effectiveness:10},{name:'Worms',effectiveness:9},{name:'Maggots',effectiveness:8},{name:'Bread Flake',effectiveness:8},{name:'Pellets',effectiveness:7}],rigs:[{name:'Method Feeder',description:'Loaded feeder packed with groundbait and hookbait mounted on short hair'},{name:'Float Rig',description:'Waggler fished over baited patch at dawn'},{name:'Simple Ledger',description:'Running ledger with short hooklink fished on clean lake bottom'}],hookSizes:['10','12','14'],lineWeight:'6-10lb',legalSize:30,recordWeight:4.53,averageWeight:'1-4kg',averageLength:'30-55cm',tips:['Fish at first light for the best tench action','Look for bubbling and lily pad movement as signs of feeding tench','Prebait your swim the evening before for morning sessions','Keep noise and movement to a minimum on the bank','Tench put up a powerful fight - enjoy it but keep pressure on near weeds'],difficulty:'intermediate',rarity:'uncommon',rarityColor:'#22C55E',rarityDescription:'Requires weedy habitat and perfect early morning conditions to find.',spawnConditions:'Dense lily pad beds and muddy-bottomed lakes at dawn',catchRate:55,emoji:'\ud83c\udf3f',bestTimes:{timeOfDay:['Pre-dawn to 9am (absolute peak)','Dusk (7pm-9pm)','Night sessions in high summer'],moonPhase:'New moon and full moon boost dawn feeding activity significantly',season:'May through August prime. June and July mornings are exceptional.',temperature:'Water temp 16-22\xb0C ideal. Poor in cold water below 10\xb0C.',barometric:'High stable pressure with warm overnight temperatures. Classic tench weather.',weather:'Warm, calm, misty mornings. Still water with wisps of surface mist.'},catchingTips:['Arrive an hour before dawn to set up quietly \u2014 disturbing the swim kills the session','Watch the water surface for streams of tiny bubbles indicating feeding tench below','Rake the swim the evening before to disturb the bottom and release natural food items','Present bait on the drop with a slow-sinking waggler to intercept fish at all depths','Use a hair-rigged grain of sweetcorn with two maggots on the hair for extra attraction','Prebait with crushed hemp, corn, and a few worms three evenings before your session','Fish on clean gravel or clay bottom at the edge of weed \u2014 not in the weed itself'],commonMistakes:['Arriving too late \u2014 the first 90 minutes of light is when 80% of tench are caught','Overloading the swim with bait \u2014 tench spook easily and a small precise bed works better','Using a float that is too sensitive \u2014 tench give classic bold dips then lift bites, not tiny trembles','Fishing in the wrong depth \u2014 find where the weed gives way to clean bottom'],proTips:['In very warm summers, tench can be caught all night on boilies fished carp-style over a spodded bed \u2014 2lb+ tench are common catches','In weedy lakes, use a buoyant hookbait (plastic corn balanced with a real grain) to keep it visible just above bottom silt where tench are rooting']},{id:'bream',name:'Common Bream',commonName:'Bream',latinName:'Abramis brama',type:'coarse',habitat:'Large lakes, reservoirs, slow and medium-paced rivers with muddy beds',behaviour:'Shoal fish that move in large packs grazing on the bottom. Distinctive rolling on the surface when feeding nearby. Night feeders in summer.',bestSeasons:['Summer','Autumn'],bestWeather:'Overcast nights in summer. Warm, calm conditions generally.',baits:[{name:'Worms',effectiveness:9},{name:'Maggots',effectiveness:9},{name:'Casters',effectiveness:8},{name:'Groundbait',effectiveness:10},{name:'Bread Flake',effectiveness:7}],rigs:[{name:'Flat Method Feeder',description:'Flat bed feeder packed with groundbait, excellent for bream on still waters'},{name:'Cage Feeder',description:'Open cage feeder that releases groundbait slowly, good in rivers'},{name:'Slider Float',description:'Long-range float fishing over groundbaited spots in still waters'}],hookSizes:['10','12','14'],lineWeight:'6-8lb',legalSize:30,recordWeight:9.04,averageWeight:'0.5-3kg',averageLength:'30-60cm',tips:['Groundbait is essential - bream respond to heavy feeding','Use a flat feeder and fish at range to reach feeding shoals','Bream roll on the surface before settling to feed - watch for this','Night fishing in summer can produce bags of quality bream','Keep casting accurately to the same spot to build up groundbait'],difficulty:'beginner',rarity:'common',rarityColor:'#9CA3AF',rarityDescription:'Common shoal fish found in abundance across UK still and slow waters.',spawnConditions:'Summer nights in large lakes and slow rivers',catchRate:80,emoji:'\ud83e\udee7',bestTimes:{timeOfDay:['Night (10pm-3am) in summer','Dawn (5am-8am)','Dusk (7pm-10pm)'],moonPhase:'Full moon nights produce extraordinary bream bags \u2014 fish all night',season:'June through September. Warm summer nights are when big catches happen.',temperature:'Water temp 14-20\xb0C ideal. Night fishing in warm summer conditions.',barometric:'Stable or slowly rising pressure. Prolonged settled weather is best.',weather:'Warm still nights with cloud cover. Lightning storms can trigger feeding beforehand.'},catchingTips:['Watch the water at dusk for bream rolling \u2014 they reveal their patrol route this way','Catapult or spod several kilos of groundbait mixed with maggots, casters, and worms','Use a baitrunner or open bale arm \u2014 bream bite and move off sideways creating slack line','Cast consistently to the same spot to build a precise bait carpet, not a scatter','Two rods placed side by side 2 feet apart on the same groundbait patch doubles your options','In rivers, use a heavy cage feeder and let it swing downstream \u2014 bream follow the scent','On still nights, listen for bream rolling \u2014 the splashing sound in the dark tells you they\'ve arrived'],commonMistakes:['Not groundbaiting heavily enough \u2014 bream need large quantities of feed to commit','Using too short a hooklink \u2014 bream are skittish and a 15-18 inch tail gives them time to turn','Missing the "lift bite" \u2014 bream lift the leger weight as they feed, causing the tip to drop back','Striking too hard \u2014 bream have soft mouths and aggressive strikes tear the hook out'],proTips:['The biggest bream in a venue often move into very shallow marginal water (2-3ft) on warm summer nights \u2014 try a margin rod at close range after midnight','Pre-baiting the same spot for 3-4 nights before fishing teaches bream to patrol it confidently \u2014 a blank pre-bait session leads to an epic fishing session']},{id:'roach',name:'Roach',commonName:'Roach',latinName:'Rutilus rutilus',type:'coarse',habitat:'Rivers, canals, lakes - one of the most widespread UK coarse fish',behaviour:'Shoal fish that feed throughout the water column. Cautious in clear water. Often found near bridges and locks in rivers.',bestSeasons:['Autumn','Winter','Spring'],bestWeather:'Cold clear days in winter. Overcast conditions generally preferred.',baits:[{name:'Maggots',effectiveness:10},{name:'Casters',effectiveness:9},{name:'Hemp Seed',effectiveness:8},{name:'Bread Punch',effectiveness:8},{name:'Tares',effectiveness:7}],rigs:[{name:'Stick Float',description:'Trotting a stick float through a river swim with loose feed'},{name:'Waggler',description:'Attached at bottom only, cast to length on still or slow waters'},{name:'Pole Rig',description:'Extremely delicate presentation perfect for cautious roach'}],hookSizes:['14','16','18','20'],lineWeight:'2-4lb',legalSize:20,recordWeight:1.9,averageWeight:'0.1-0.5kg',averageLength:'15-30cm',tips:['Fine presentation wins with roach - use smallest hooks and lightest lines','Loose feeding little and often keeps roach confident','Trotting a float on rivers is the most enjoyable and effective method','Roach improve throughout winter - target them from October onwards','Add red dye to maggots for extra attraction in coloured water'],difficulty:'beginner',rarity:'common',rarityColor:'#9CA3AF',rarityDescription:'Extremely widespread and abundant UK coarse fish found in almost any water.',spawnConditions:'Year-round in most rivers, canals, and lakes',catchRate:85,emoji:'\ud83d\udd34',bestTimes:{timeOfDay:['Midmorning (9am-12pm)','Early afternoon (12pm-3pm)','Mild winter days all day'],moonPhase:'Waning gibbous and last quarter see good roach feeding in rivers',season:'October through March. Quality improves as the season progresses.',temperature:'Water temp 4-12\xb0C fine. Hardy fish that feed throughout UK winter.',barometric:'Stable high pressure with crisp cold days. Classic roach conditions.',weather:'Cold, bright winter days with frost overnight. Steady clear conditions.'},catchingTips:['Trundle a stick float through the swim at the exact pace of the current \u2014 not faster or slower','Feed maggots at the same rate as you are catching \u2014 if bites slow, feed more','Use a size 18 or 20 hook to single maggot in clear cold water for shy winter roach','In still waters, let the hookbait settle on the bottom rather than fishing "on the drop"','Switch to casters from maggots to weed out small fish and target quality roach','Hemp seed fed regularly will hold roach in the swim for hours on rivers'],commonMistakes:['Fishing too heavy \u2014 4lb line is the maximum in most situations, 2lb is often better','Striking too slowly \u2014 roach eject baits quickly, a fast flick of the wrist is needed','Not matching the float to the flow \u2014 an over-shotted float drags the bait unnaturally','Feeding too much at once \u2014 little and often is the golden rule for roach fishing'],proTips:['The biggest river roach in the UK are caught in the coldest, clearest winter conditions on tiny bread punch and gossamer lines \u2014 challenging but very rewarding','On canals, find the deepest section (usually the centre channel) and fish a tight pole line at 11-13 metres with single maggot \u2014 better fish avoid the shallower margins']},{id:'barbel',name:'Barbel',commonName:'Barbel',latinName:'Barbus barbus',type:'coarse',habitat:'Fast-flowing rivers with gravel beds - the Trent, Severn, Kennet, Great Ouse',behaviour:'Power house fish that love fast, well-oxygenated water. Feed on the gravel bottom using sensitive barbels. Fight extremely hard.',bestSeasons:['Summer','Autumn'],bestWeather:'After summer rain when rivers run coloured and level rises slightly.',baits:[{name:'Meat (Spam)',effectiveness:10},{name:'Pellets',effectiveness:9},{name:'Boilies',effectiveness:8},{name:'Hemp',effectiveness:8},{name:'Worms',effectiveness:7}],rigs:[{name:'Running Ledger',description:'Simple running lead on heavy mono with short hooklink, fished on gravel'},{name:'Feeder Rig',description:'Cage feeder loaded with hemp and pellets, short hair-rigged hookbait'},{name:'Link Ledger',description:'Paternoster style with link to prevent fish feeling resistance'}],hookSizes:['6','8','10'],lineWeight:'10-15lb',legalSize:30,recordWeight:8.9,averageWeight:'2-6kg',averageLength:'40-70cm',tips:['Barbel fishing is best after dark or in low light conditions','Fish in or near the crease where fast and slow water meet','Use heavy leads (2-3oz) to hold bottom in fast water','Always rest a barbel fully before returning - they exhaust completely','The best spots have gravel bottoms with chub, good oxygen levels'],difficulty:'intermediate',rarity:'rare',rarityColor:'#3B82F6',rarityDescription:'Fast-water specialist requiring the right river conditions and after-dark effort.',spawnConditions:'Fast gravel-bedded rivers after summer rain',catchRate:35,emoji:'\ud83d\udcaa',bestTimes:{timeOfDay:['Dusk onwards (7pm-midnight) absolute peak','Evening (5pm-8pm)','After overnight rain at dawn'],moonPhase:'Full moon nights on rivers with good colour \u2014 superb barbel sessions',season:'June through October. Coloured autumn rivers after rain are exceptional.',temperature:'Water temp 12-20\xb0C ideal. Fast rivers stay well-oxygenated in heat.',barometric:'Falling pressure before rain is excellent. Rising river conditions after rain superb.',weather:'Overcast evenings after summer rain. Some colour in the water is a bonus.'},catchingTips:['Introduce a carpet of hemp and pellets upstream of your swim and let it drift down','Fish the bait tight to the crease where fast white water meets the calmer eddy','Use a 3oz lead minimum to hold bottom in fast water \u2014 barbel feel resistance and drop lighter rigs','Hair-rig a chunk of Spam or meat \u2014 barbel mouth it repeatedly before the hook finds purchase','Keep your rod tip low and pointed at the bait \u2014 barbel bites are savage downstream pulls','After hooking a barbel, let it run upstream initially before applying side-strain to turn it','Rest baited spots for 20-30 minutes after disturbance \u2014 barbel return once calm is restored'],commonMistakes:['Using too light a lead \u2014 barbel live in fast water and a 1oz lead simply washes downstream','Striking barbel bites \u2014 the rod will be nearly wrenched from your hands; just lift into the fish','Not reviving barbel properly \u2014 they exhaust completely and must be held upright until fully recovered','Fishing in daylight only \u2014 missing the productive evening and night sessions'],proTips:['On heavily fished rivers, switch to an unusual bait like a large lobworm or a 20mm boilie \u2014 barbel become educated to common Spam and pellet presentations very quickly','Wade quietly into the river at dusk and roll meat or paste downstream under overhanging banks you cannot reach from the bank \u2014 underfished territory holds the biggest barbel']},{id:'chub',name:'Chub',commonName:'Chub',latinName:'Squalius cephalus',type:'coarse',habitat:'Rivers with moderate flow, undercut banks, overhanging willows, weirpools',behaviour:'Greedy fish that will eat almost anything. Spooky in clear water, bold in coloured water. Often found in shoals near cover.',bestSeasons:['Summer','Autumn','Winter'],bestWeather:'Overcast with a touch of colour in the water. Hardy fish that feed year-round.',baits:[{name:'Cheese Paste',effectiveness:10},{name:'Meat (Spam)',effectiveness:9},{name:'Bread Flake',effectiveness:9},{name:'Crayfish',effectiveness:8},{name:'Worms',effectiveness:8}],rigs:[{name:'Freeline',description:'No weight at all - bait drifts naturally downstream to waiting chub'},{name:'Float Rig',description:'Trotted float carrying bread or cheese past likely chub lies'},{name:'Simple Ledger',description:'Light ledger in deeper holes and pools'}],hookSizes:['6','8','10'],lineWeight:'8-12lb',legalSize:25,recordWeight:4.4,averageWeight:'0.5-3kg',averageLength:'30-60cm',tips:['Stealthy approach is essential - chub bolt at the slightest shadow','Try floating bread on the surface under overhanging trees','Chub love cheese paste - make your own with mature stilton','Walk the river and look before you fish - spot fish first','Cold winters can produce the biggest chub of the year'],difficulty:'beginner',rarity:'uncommon',rarityColor:'#22C55E',rarityDescription:'River fish requiring approach craft and quality river habitat.',spawnConditions:'Overhanging willows, undercut banks, weirpools',catchRate:60,emoji:'\ud83c\udf0a',bestTimes:{timeOfDay:['Dawn (6am-9am)','Dusk (4pm-7pm)','Midday in winter when water is clearest'],moonPhase:'Less dependent on moon phase \u2014 chub feed whenever conditions suit',season:'Year-round but January and February produce the biggest specimens.',temperature:'Hardy in all temperatures. Winter floods with 6-8\xb0C water can be superb.',barometric:'Stable or slowly falling pressure. Good in winter lows.',weather:'Overcast days, ideally with some colour in the water from recent rain.'},catchingTips:['Crouch low when approaching the river \u2014 a standing silhouette at 50 yards will spook every chub','Freeline a piece of crust under an overhanging tree and let it drift naturally into the shadow','In coloured water, chub are far less cautious \u2014 use this opportunity to fish closer and heavier','Make a large ball of cheese paste (strong cheddar, flour, and a little turmeric) for a devastating bait','Trot a waggler through long glides with bread flake at half depth to find fish scattered through the swim','In winter floods, find slacks and eddies behind bridge piers \u2014 chub pack into these refuges'],commonMistakes:['Standing up while approaching the swim \u2014 chub have a 180-degree field of vision and bolt instantly','Fishing in the same spot after spooked fish \u2014 wait 20 minutes minimum before recasting','Not varying bait size \u2014 a tiny piece of flake on a size 14 often outfishes a large piece on a size 6'],proTips:['On clear winter days, polarised glasses let you spot individual chub holding in deep pools \u2014 watch their reaction to dropped crusts from a bridge to understand exactly where they are lying','Luncheon meat cubed to 12mm and trimmed square on all sides sinks slowly and perfectly \u2014 the neat presentation is far more effective than torn or rounded pieces']},{id:'salmon',name:'Atlantic Salmon',commonName:'Salmon',latinName:'Salmo salar',type:'game',habitat:'Fast, clean, cold rivers during migration runs - the Tay, Wye, Test, Exe',behaviour:'Anadromous fish that returns from ocean to natal river to spawn. Does not feed in freshwater - responds to irritation or aggression. Lies in lies behind boulders and in pools.',bestSeasons:['Winter','Spring','Autumn'],bestWeather:'Overcast days after rain when river is fining down from a spate.',baits:[{name:'Fly (Tube)',effectiveness:10},{name:'Fly (Single)',effectiveness:9},{name:'Spinner',effectiveness:8},{name:'Shrimp',effectiveness:7},{name:'Prawn',effectiveness:7}],rigs:[{name:'Fly Fishing',description:'Double-handed or single-handed rod presenting a fly across and downstream'},{name:'Spinning',description:'Flying C, Toby, or similar lures worked through salmon lies'},{name:'Bait Fishing',description:'Shrimp or prawn presented on a single hook, where permitted'}],hookSizes:['6','8','10','12'],lineWeight:'15-20lb',legalSize:45,recordWeight:29.03,averageWeight:'3-12kg',averageLength:'60-100cm',tips:['Salmon require a licence and rod licence - always fish legally','Fish the fly across and downstream - let it swing through the lie','High and coloured water calls for large, bright flies','Low clear water needs small, dark flies fished slowly','Salmon do not feed in freshwater - they react to stimuli, so vary the retrieve'],difficulty:'expert',rarity:'legendary',rarityColor:'#F59E0B',rarityDescription:'Migratory fish that returns to birthplace river. Runs are unpredictable and brief.',spawnConditions:'Clean spate rivers during autumn and spring runs',catchRate:8,emoji:'\ud83d\udc1f',bestTimes:{timeOfDay:['Morning (7am-11am)','Evening (5pm-8pm)','Overcast midday sessions in autumn'],tideState:'Fresh run fish enter on spring tides \u2014 fish lower pools when tide pushes in',moonPhase:'Spring tides (new and full moon) bring fresh fish off the sea into rivers',season:'River dependent. Scottish rivers: January-October. Southern chalk streams: April-September.',temperature:'Water temp 7-14\xb0C ideal for fly. Warmer water needs smaller flies and slower presentation.',barometric:'Falling pressure with rain is perfect \u2014 salmon run hard in fresh spate conditions.',weather:'Overcast day with rain approaching. River fining down 24-48h after spate is classic.'},catchingTips:['Wade quietly and position so your fly swings across and downstream through the lie naturally','In high cold water, fish a large bright tube fly (Cascade, Ally\'s Shrimp) deep and slow','In low clear summer water, switch to a size 10-14 single and fish a floating or intermediate line','Cover every inch of a productive pool \u2014 salmon lie in very specific spots and casting is precise','After your fly has swung to the dangle, leave it stationary for 10 seconds \u2014 takes often come here','Change flies every 30 minutes if no response \u2014 fresh salmon are stimulated by something new'],commonMistakes:['Fishing the same fly all day \u2014 salmon in a pool have seen it, change pattern, size, and colour','Wading too deep too quickly \u2014 disturbing the tail of the pool sends fish upstream before you reach them','Not respecting the "taking time" \u2014 salmon are more likely to take in the first hour of new water levels','Missing the take \u2014 hold the fly slack not tight; salmon that feel resistance spit the hook immediately'],proTips:['A salmon lying in a pool for days is stale and near impossible \u2014 target fresh-run fish in the lowest pools immediately after a spate, before they rest and become dour','On pressured beats, change to an unusual colour combination (orange and black, yellow and red) that the fish have not seen from other anglers that season \u2014 often provokes a take from a fish that has ignored everything conventional']},{id:'seabass',name:'European Sea Bass',commonName:'Sea Bass',latinName:'Dicentrarchus labrax',type:'sea',habitat:'Rocky coastlines, estuaries, piers and harbours, surf beaches across UK',behaviour:'Predatory sea fish that hunt baitfish in tidal flows. Follow tide up estuaries and onto beaches at high tide. Hunt in small groups around structure.',bestSeasons:['Summer','Autumn'],bestWeather:'Rough seas after a blow, or calm clear nights around high tide.',baits:[{name:'Sandeel',effectiveness:10},{name:'Ragworm',effectiveness:9},{name:'Plugs/Lures',effectiveness:9},{name:'Squid',effectiveness:8},{name:'Peeler Crab',effectiveness:8}],rigs:[{name:'Pulley Rig',description:'Bait on single hook at bottom, pulley reduces snagging on rocky ground'},{name:'Lure Fishing',description:'Walking the dog surface lures or soft plastics on light tackle'},{name:'Running Ledger',description:'Simple running ledger with worm or squid on sandy beaches'}],hookSizes:['2','1','1/0','2/0'],lineWeight:'12-20lb',legalSize:42,recordWeight:8.33,averageWeight:'1-4kg',averageLength:'40-70cm',tips:['Bass have strict size limits - always measure before keeping (42cm minimum)','Catch and release is strongly encouraged for this recovering species','Fish lures at night around structure for the best sport','The hour before and after high tide in estuaries can be exceptional','Stealth is key on clear nights - bass are very line-shy'],difficulty:'intermediate',rarity:'epic',rarityColor:'#8B5CF6',rarityDescription:'Powerful inshore predator with strict size limits. Elusive and challenging to locate.',spawnConditions:'Rocky coastlines, estuaries on spring tides during summer',catchRate:18,emoji:'\ud83c\udf0a',bestTimes:{timeOfDay:['Night (10pm-2am) for lure fishing','Dawn (5am-8am)','2 hours either side of high tide'],tideState:'Incoming tide: 2 hours before to 1 hour after high. Estuaries best on flooding tide.',moonPhase:'Spring tides (new and full moon) push bass close inshore and into estuaries',season:'June through October. Peak in August-September as sea temperatures peak.',temperature:'Sea temp 15-20\xb0C ideal. Below 12\xb0C bass become lethargic and move offshore.',barometric:'Rough weather followed by calming seas \u2014 bass hunt in the disturbed water.',weather:'Calm nights with sea swell settling. Clear water after storms. First calm night after rough weather.'},catchingTips:['Fish the very first calm night after a storm \u2014 disturbed water and washed-out sandeels bring bass inshore','Work a surface plug along rock edges at night \u2014 bass blow up on them in incredibly shallow water','In estuaries, position to cast uptide into the current and let the bait swing downstream into the channel','Use fluorocarbon leader of 20-25lb \u2014 bass have excellent vision and mono leader costs takes','Vary retrieve speed constantly with soft plastics \u2014 bass often follow but only commit when speed changes','Fish the gullies and channels that drain on the ebb tide \u2014 bass trap baitfish in these features','On open surf beaches, look for where waves are breaking unevenly \u2014 that\'s where sandeels shelter'],commonMistakes:['Fishing at dead low water \u2014 bass follow the tide and are often far offshore at low','Using braided line without a fluorocarbon leader \u2014 bass see braid and avoid the bait','Keeping undersized fish \u2014 bass are a recovering species and every legal fish returned matters','Fishing with too heavy a rod \u2014 light spinning gear (10-20g lure weight) gives much more sport and sensitivity'],proTips:['The best bass fishing of the year often happens in September and October when the fish are at their heaviest pre-winter \u2014 target warm nights on spring tides','Stand perfectly still while lure fishing at night \u2014 bass hunt by vibration and noise, and a stationary angler working lures from the same spot is far less disruptive than someone constantly repositioning']},{id:'rainbow-trout',name:'Rainbow Trout',commonName:'Rainbow Trout',latinName:'Oncorhynchus mykiss',type:'game',habitat:'Stocked reservoirs, chalk streams, stillwater fisheries. Clear, cold, well-oxygenated water.',behaviour:'Aggressive predators that feed on insects, small fish and crustaceans. Rise freely to dry flies in warm weather.',bestSeasons:['Spring','Autumn'],bestWeather:'Overcast days with light winds. Hatches of flies trigger feeding frenzies.',baits:[{name:'Dry Fly',effectiveness:9},{name:'Nymph',effectiveness:10},{name:'Lure (Booby)',effectiveness:8},{name:'Power Bait',effectiveness:7}],rigs:[{name:'Dry Fly Setup',description:'Light fly rod 5wt, 9ft leader tapering to 5X tippet'},{name:'Indicator Nymph',description:'Strike indicator 1.5x depth of water, weighted nymph'},{name:'Sink Line Lure',description:'Fast sinking line with booby or goldhead lure'}],hookSizes:['8','10','12','14'],lineWeight:'4-6lb',legalSize:25,recordWeight:21.77,averageWeight:'0.5-3kg',averageLength:'35-60cm',tips:['Match the hatch \u2014 observe what insects are on the water and select the closest fly pattern','Present the fly upstream and let it drift naturally without drag','On stillwaters, vary your retrieve speed and depth until you find active fish'],difficulty:'intermediate',rarity:'uncommon',rarityColor:'#22C55E',rarityDescription:'Stocked in reservoirs and fisheries throughout the UK.',spawnConditions:'Stocked reservoirs and chalk streams',catchRate:58,emoji:'\ud83c\udf08',bestTimes:{timeOfDay:['Dawn','Dusk','Overcast afternoons'],moonPhase:'Less moon-dependent than coarse fish',season:'Spring and autumn peak. Summer evenings excellent.',temperature:'Best 8-14\xb0C. Very cold or warm water slows feeding.',barometric:'Stable or rising pressure',weather:'Overcast, light drizzle often triggers insect hatches'},catchingTips:['Use polarised sunglasses to spot rising fish','Approach cautiously \u2014 trout spook easily'],commonMistakes:['Splashy casts that spook fish','Drag on the dry fly','Using too heavy a tippet'],proTips:['Add a dropper nymph below a dry fly (duo rig) to cover two zones at once']},{id:'brown-trout',name:'Brown Trout',commonName:'Brown Trout',latinName:'Salmo trutta',type:'game',habitat:'Fast rivers, chalk streams, upland streams, Scottish lochs. Needs clean, cold water.',behaviour:'Wary, territorial fish. Wild brownies are notoriously difficult to catch. Hold in lies behind rocks and in pools.',bestSeasons:['Spring','Summer'],bestWeather:'Overcast days with evening fly hatches. Avoid bright sunshine \u2014 fish become nocturnal.',baits:[{name:'Dry Fly',effectiveness:10},{name:'Nymph',effectiveness:9},{name:'Worm',effectiveness:7},{name:'Spinner',effectiveness:6}],rigs:[{name:'Dry Fly',description:'Fine tippet 5X-6X, upstream presentation'},{name:'Czech Nymph',description:'Short line, tungsten nymphs, feel for takes'}],hookSizes:['10','12','14','16'],lineWeight:'3-5lb',legalSize:25,recordWeight:19.8,averageWeight:'0.5-2kg',averageLength:'30-55cm',tips:['Wild brown trout are cunning \u2014 perfect presentation is essential','Fish upstream and cover water quietly'],difficulty:'expert',rarity:'rare',rarityColor:'#3B82F6',rarityDescription:'Wild brownies are notoriously difficult. Requires clean rivers and perfect fly presentation.',spawnConditions:'Clean, cold, fast-flowing rivers and upland streams',catchRate:38,emoji:'\ud83d\udfe4',bestTimes:{timeOfDay:['Evening'],moonPhase:'Less dependent',season:'March-September on rivers',temperature:'8-13\xb0C ideal',barometric:'Stable',weather:'Overcast evenings with fly hatches'},catchingTips:['Stalk fish in clear water with polaroids','Present fly on the first cast \u2014 second cast often spooks them'],commonMistakes:['False casting too many times','Heavy leader','Fishing directly over the fish'],proTips:['Fish the evening rise \u2014 wild brownies often only feed on surface during the hatch']},{id:'eel',name:'European Eel',commonName:'Eel',latinName:'Anguilla anguilla',type:'coarse',habitat:'Rivers, canals, ponds and lakes with soft, silty bottoms. Hides in holes, drains, and dense weed.',behaviour:'Nocturnal bottom feeder. Critically endangered \u2014 handle with extreme care and always return. Uses scent to find food.',bestSeasons:['Summer'],bestWeather:'Warm summer nights. After rain when smell disperses well.',baits:[{name:'Lobworm',effectiveness:10},{name:'Deadbait (fish section)',effectiveness:9},{name:'Maggots',effectiveness:7}],rigs:[{name:'Simple Ledger',description:'Running lead, size 6 hook, worm on hair or direct'}],hookSizes:['4','6','8'],lineWeight:'8-12lb',legalSize:0,recordWeight:5.08,averageWeight:'0.5-1.5kg',averageLength:'50-90cm',tips:['Fish at night \u2014 eels are almost exclusively nocturnal','Use a landing net \u2014 eels are slippery and difficult to handle'],difficulty:'beginner',rarity:'rare',rarityColor:'#3B82F6',rarityDescription:'Critically endangered and nocturnal. Hard to locate and requires specialist night tactics.',spawnConditions:'Silty ponds, rivers and canals on warm summer nights',catchRate:25,emoji:'\ud83d\udc0d',bestTimes:{timeOfDay:['Night'],moonPhase:'Dark nights preferred',season:'June to September',temperature:'Warm water 15\xb0C+',barometric:'Any',weather:'Warm and overcast'},catchingTips:['Target drainage ditches and silty canal margins','Leave the rod on a rest with the bale arm open'],commonMistakes:['Striking too soon','Not using a mesh landing net'],proTips:['Critically endangered \u2014 always return immediately and handle minimally']},{id:'zander',name:'Zander',commonName:'Zander',latinName:'Sander lucioperca',type:'coarse',habitat:'Large slow rivers, fenland drains, reservoirs. Prefers turbid (coloured) water.',behaviour:'Pack hunters at dusk. Related to perch but with pike-like teeth. Ambush predators in coloured water.',bestSeasons:['Autumn','Winter'],bestWeather:'Low light conditions, overcast or dusk/dawn. Coloured water is an advantage.',baits:[{name:'Small roach deadbait',effectiveness:10},{name:'Soft plastic lure',effectiveness:9},{name:'Small spinner',effectiveness:7}],rigs:[{name:'Wire Trace Deadbait',description:'Light wire trace 10-15lb, small treble hooks'},{name:'Jig Head',description:'5-10g jig head with 3-4 inch shad lure'}],hookSizes:['6','8'],lineWeight:'10-15lb',legalSize:0,recordWeight:8.85,averageWeight:'1-4kg',averageLength:'40-80cm',tips:['Target Norfolk Broads and fenland drains','Fish at dusk \u2014 prime feeding time'],difficulty:'intermediate',rarity:'epic',rarityColor:'#8B5CF6',rarityDescription:'Ambush predator of coloured water. Requires specific drains and low-light conditions.',spawnConditions:'Fenland drains and slow turbid rivers at dusk',catchRate:15,emoji:'\ud83e\udd88',bestTimes:{timeOfDay:['Dusk','Dawn','Night'],moonPhase:'Dark phases best',season:'Autumn and winter',temperature:'Cold water productive',barometric:'Falling',weather:'Overcast, low light'},catchingTips:['Dead roach on a light wire trace','Drop shot with small shad lure near bottom structure'],commonMistakes:['Using baits that are too large','Fishing in bright sunny conditions'],proTips:['Zander follow prey fish into warm water outflows from power stations in winter']},{id:'crucian-carp',name:'Crucian Carp',commonName:'Crucian Carp',latinName:'Carassius carassius',type:'coarse',habitat:'Weedy ponds, estate lakes and quiet backwaters. True crucians are increasingly rare.',behaviour:'Shy, secretive feeders in thick weed. Feed delicately \u2014 bites often lift the float rather than pulling it under.',bestSeasons:['Summer'],bestWeather:'Hot, still summer days. Early morning before the heat.',baits:[{name:'Sweetcorn',effectiveness:9},{name:'Maggots',effectiveness:8},{name:'Bread',effectiveness:8},{name:'Worm',effectiveness:7}],rigs:[{name:'Sensitive Waggler',description:'Light float, very small hook, fine line for bite detection'}],hookSizes:['14','16','18'],lineWeight:'3-4lb',legalSize:0,recordWeight:2.81,averageWeight:'0.5-1.5kg',averageLength:'20-35cm',tips:['Use very sensitive float tackle \u2014 bites can be extremely delicate','Fish close to lily pads and reed margins'],difficulty:'intermediate',rarity:'rare',rarityColor:'#3B82F6',rarityDescription:'True wild crucians are increasingly rare. Finding a pure strain lake is the challenge.',spawnConditions:'Very specific weedy ponds with true crucian populations',catchRate:30,emoji:'\ud83d\udfe1',bestTimes:{timeOfDay:['Dawn','Dusk'],moonPhase:'Full moon',season:'June to September',temperature:'18\xb0C+ ideal',barometric:'High and stable',weather:'Warm and still'},catchingTips:['Plumb the depth carefully and set float to have bait just touching bottom','Watch for the float to lift \u2014 classic crucian bite'],commonMistakes:['Using too coarse tackle','Splashing baiting','Missing lifts on the float'],proTips:['True wild crucians are rare \u2014 many fisheries hold hybrids. A pure crucian is a prize catch']},{id:'rudd',name:'Rudd',commonName:'Rudd',latinName:'Scardinius erythrophthalmus',type:'coarse',habitat:'Weedy lakes, meres, slow rivers and canals. Prefers the upper layers of water.',behaviour:'Surface and mid-water feeder. Beautiful golden fish with red fins. Often shoals near surface in summer.',bestSeasons:['Spring','Summer'],bestWeather:'Warm sunny days \u2014 rudd love surface feeding when conditions are warm.',baits:[{name:'Floating Bread',effectiveness:10},{name:'Dry Fly',effectiveness:8},{name:'Maggots',effectiveness:8}],rigs:[{name:'Surface Float',description:'Waggler set shallow or on the surface with floating bread'}],hookSizes:['12','14','16'],lineWeight:'3-5lb',legalSize:0,recordWeight:2.18,averageWeight:'0.3-0.8kg',averageLength:'20-30cm',tips:['Fish the surface in summer mornings','Rudd will take a fly rod cast with a dry fly'],difficulty:'beginner',rarity:'uncommon',rarityColor:'#22C55E',rarityDescription:'Surface feeder found in weedy lakes and meres. Beautiful but requires calm, warm conditions.',spawnConditions:'Weedy lake surfaces on warm summer mornings',catchRate:62,emoji:'\ud83d\udd34',bestTimes:{timeOfDay:['Morning','Evening'],moonPhase:'Any',season:'Late spring through summer',temperature:'18\xb0C+',barometric:'High',weather:'Warm and sunny'},catchingTips:['Throw a few pieces of floating bread to attract a shoal','Cast beyond the rising fish and draw the bread towards them'],commonMistakes:['Fishing too deep \u2014 rudd are not bottom feeders','Approaching too close and spooking the shoal'],proTips:['Rudd are a fantastic light tackle fly rod target \u2014 great fun on a 4wt rod']},{id:'dace',name:'Dace',commonName:'Dace',latinName:'Leuciscus leuciscus',type:'coarse',habitat:'Clean, gravelly rivers. Shoals in the faster runs and riffles.',behaviour:'Fast, active shoal fish. Feed on insects, larvae and small invertebrates throughout the water column.',bestSeasons:['Autumn','Winter'],bestWeather:'Clear, bright days on fast rivers. Good sport in cold conditions when other species slow down.',baits:[{name:'Maggots',effectiveness:10},{name:'Casters',effectiveness:9},{name:'Small worm',effectiveness:7}],rigs:[{name:'Stickfloat',description:'Trotting a stickfloat through a gravel run \u2014 classic river fishing'}],hookSizes:['16','18','20'],lineWeight:'2-3lb',legalSize:0,recordWeight:.65,averageWeight:'0.1-0.3kg',averageLength:'15-25cm',tips:['Trot a stick float through gravel runs for exciting sport','Loose feed maggots continuously upstream to hold the shoal'],difficulty:'beginner',rarity:'common',rarityColor:'#9CA3AF',rarityDescription:'Common river fish found in clean gravelly rivers across the UK.',spawnConditions:'Gravel runs and riffles of clean rivers',catchRate:72,emoji:'\ud83d\udca8',bestTimes:{timeOfDay:['Mid-morning','Afternoon'],moonPhase:'Any',season:'Autumn and winter best',temperature:'5-12\xb0C',barometric:'Any',weather:'Bright and clear'},catchingTips:['Trot a stickfloat down the current and follow it with the rod','Strike quickly \u2014 dace are fast!'],commonMistakes:['Using hooks that are too large','Not loose feeding enough'],proTips:['Dace are the perfect species for learning river float fishing technique']},{id:'gudgeon',name:'Gudgeon',commonName:'Gudgeon',latinName:'Gobio gobio',type:'coarse',habitat:'Gravel-bottomed rivers, canals and lakes. Prefers flowing water with clean gravel.',behaviour:'Bottom feeder. Forms large shoals over gravel. Feeds by taste and smell, rooting through the substrate.',bestSeasons:['Spring','Summer','Autumn'],bestWeather:'Any weather \u2014 very obliging fish, great for beginners and junior anglers.',baits:[{name:'Single maggot',effectiveness:10},{name:'Small worm',effectiveness:9},{name:'Caster',effectiveness:8}],rigs:[{name:'Float Rig',description:'Small float, size 18-20 hook, single maggot on the bottom'}],hookSizes:['18','20'],lineWeight:'2lb',legalSize:0,recordWeight:.13,averageWeight:'30-80g',averageLength:'10-15cm',tips:['Scrape the gravel bottom to release particles \u2014 attracts gudgeon quickly','Great species for introducing children to fishing'],difficulty:'beginner',rarity:'common',rarityColor:'#9CA3AF',rarityDescription:'Very common bottom-feeder found in most rivers and canals.',spawnConditions:'Gravel-bottomed rivers and canals',catchRate:78,emoji:'\u26aa',bestTimes:{timeOfDay:['Any time'],moonPhase:'Any',season:'Spring through autumn',temperature:'Any',barometric:'Any',weather:'Any'},catchingTips:['Fish with a tiny hook and single maggot on the bottom','Use a waggler with most weight at the bottom for quick bites'],commonMistakes:['Using too large a hook and bait','Not fishing directly on the bottom'],proTips:['Gudgeon are an excellent bait for perch and pike when used as a live or dead bait']},{id:'flounder',name:'Flounder',commonName:'Flounder',latinName:'Platichthys flesus',type:'sea',habitat:'Estuaries, river mouths, sandy and muddy shorelines. The only flatfish that enters fresh water.',behaviour:'Lies flat on the seabed, camouflaged. Feeds on worms, crustaceans and small fish. Moves with tides.',bestSeasons:['Autumn','Winter','Spring'],bestWeather:'Flood tides over sandy/muddy ground. Stained water favours catches.',baits:[{name:'Ragworm',effectiveness:10},{name:'Lugworm',effectiveness:9},{name:'Peeler crab',effectiveness:9}],rigs:[{name:'Running Ledger',description:'Simple running ledger with 18 inch fluorocarbon trace'},{name:'Flowing Trace',description:'Long flowing trace in estuaries to allow natural movement'}],hookSizes:['2','4','6'],lineWeight:'10-15lb',legalSize:25,recordWeight:2.32,averageWeight:'0.3-1kg',averageLength:'25-45cm',tips:['Fish estuaries on the flood tide \u2014 flounder move up with the tide to feed','A running lead with a long trace works well in estuary currents'],difficulty:'beginner',rarity:'uncommon',rarityColor:'#22C55E',rarityDescription:'Flatfish that enters estuaries and even freshwater. Timing the tide is key.',spawnConditions:'Estuaries and muddy shorelines on flood tides',catchRate:52,emoji:'\ud83d\udc21',bestTimes:{timeOfDay:['2 hours each side of high tide'],moonPhase:'Spring tides',season:'Autumn to spring',temperature:'Cold water tolerated',barometric:'Any',weather:'Any, slightly coloured water helpful'},catchingTips:['Cast uptide and let the bait swing around in the current','A spoon or blade above the trace adds attraction'],commonMistakes:['Fishing at low water \u2014 wait for the flood tide','Using baits that are too large'],proTips:['Flounder can be caught from freshwater rivers several miles from the sea in winter']},{id:'bleak',name:'Bleak',commonName:'Bleak',latinName:'Alburnus alburnus',type:'coarse',habitat:'Rivers, lakes and canals with open water. Shoals near the surface.',behaviour:'Tiny silver surface feeder. Huge shoals intercept falling particles at the surface.',bestSeasons:['Spring','Summer'],bestWeather:'Warm, still conditions when surface feeding is visible.',baits:[{name:'Single maggot',effectiveness:10},{name:'Pinkie',effectiveness:9},{name:'Tiny bit of bread',effectiveness:7}],rigs:[{name:'Pole Float',description:'Tiny pole float set very shallow, tiny hook, single maggot'}],hookSizes:['20','22'],lineWeight:'1.5lb',legalSize:0,recordWeight:.13,averageWeight:'15-40g',averageLength:'8-15cm',tips:['Bleak are the fastest biting fish in UK waters \u2014 you need to strike quickly','Great fun on a light pole or waggler rod'],difficulty:'beginner',rarity:'common',rarityColor:'#9CA3AF',rarityDescription:'Tiny silver fish present in massive shoals on most rivers and canals.',spawnConditions:'Open water of rivers and lakes in warm weather',catchRate:88,emoji:'\u26a1',bestTimes:{timeOfDay:['Any'],moonPhase:'Any',season:'Spring and summer',temperature:'15\xb0C+',barometric:'Any',weather:'Warm and still'},catchingTips:['Throw in small amounts of loose feed every few seconds to hold the shoal','Use the smallest hook possible'],commonMistakes:['Fishing too deep','Using too large a hook and bait','Feeding too much at once'],proTips:['In match fishing, catching 1-2 bleak per minute adds up quickly \u2014 a great skill in summer competitions']},{id:'wels_catfish',name:'Wels Catfish',commonName:'Wels Catfish',latinName:'Silurus glanis',type:'coarse',rarity:'mythic',rarityColor:'#EC4899',rarityDescription:'Europe\'s largest freshwater predator. Fish over 2m exist in European rivers like the Ebro and Rhine. An encounter is once in a lifetime.',spawnConditions:'Large, deep European rivers with abundant prey fish. Primarily nocturnal.',catchRate:3,habitat:'Large deep European rivers and lakes \u2014 the Ebro, Rhine, Danube, and Po.',behaviour:'Nocturnal ambush predator. Uses lateral line to detect vibrations. Hunts in darkness, targeting large prey including waterfowl.',bestSeasons:['Summer','Autumn'],bestWeather:'Warm summer nights with no moon. Stable high pressure.',baits:[{name:'Whole deadfish',effectiveness:10},{name:'Giant rubber shad lure',effectiveness:9},{name:'Clonk and worm',effectiveness:9},{name:'Live bream',effectiveness:8},{name:'Chicken liver',effectiveness:7}],rigs:[{name:'Deadbait ledger',description:'Heavy running ledger with whole large deadfish on strong wire trace'},{name:'Lure cast',description:'Giant 30cm+ rubber shad on heavy 100g+ jig head worked slowly near bottom'},{name:'Clonk rig',description:'Traditional surface-noise lure used to attract catfish from distance'}],hookSizes:['6/0','8/0','10/0'],lineWeight:'60-100lb braid',legalSize:0,recordWeight:130,averageWeight:'20-80kg',averageLength:'100-200cm',tips:['Use a clonk to create surface noise \u2014 catfish respond to vibration through their lateral line','Fish after midnight in summer \u2014 wels are most active between midnight and dawn','Guide essential for River Ebro \u2014 local knowledge of pools is everything','Strong, heavy tackle is non-negotiable \u2014 a large wels can pull a boat','Stay very still \u2014 vibrations from movement will spook these highly sensitive fish'],difficulty:'expert',emoji:'\ud83d\udc20',bestTimes:{timeOfDay:['Midnight to dawn (absolute peak)','Dusk (9pm-midnight)'],moonPhase:'Dark new moon nights \u2014 catfish feed more boldly in darkness',season:'June through September on major European rivers.',temperature:'Water temp 20\xb0C+ ideal. Cold water shuts them down.',barometric:'Stable high pressure in warm summer conditions.',weather:'Warm, calm, dark nights. No rain, no moon.'},catchingTips:['Anchor upstream of a known catfish pool and lower a whole deadfish to the bottom','Work a giant rubber shad very slowly along the river bottom \u2014 stop-start retrieve','Night vision helps to spot surface swirls revealing feeding catfish'],commonMistakes:['Using tackle that is too light \u2014 a 50kg catfish will destroy normal coarse gear','Fishing in daylight \u2014 wels are almost exclusively nocturnal in pressured waters','Not having a proper catfish unhooking and weighing system prepared'],proTips:['River Ebro in Spain is the best accessible venue. Book a guided week-long trip \u2014 local guides know every pool','Clonking (striking a wooden tool on the water surface) mimics the sound of frogs and triggers violent attacks from nearby catfish']},{id:'arapaima',name:'Arapaima',commonName:'Arapaima',latinName:'Arapaima gigas',type:'coarse',rarity:'mythic',rarityColor:'#EC4899',rarityDescription:'One of the world\'s largest freshwater fish. Can reach 3m and 200kg. An ancient species unchanged for millions of years.',spawnConditions:'Amazon and Orinoco river systems during dry season when fish are concentrated.',catchRate:3,habitat:'Amazon and Orinoco river basins \u2014 flooded forests, oxbow lakes, and main river channels.',behaviour:'Air-breathing fish that must surface every 5-15 minutes. This gives away its location. Aggressive ambush predator targeting large fish.',bestSeasons:['Dry season (June-November)'],bestWeather:'Clear dry season conditions when water levels fall and fish concentrate.',baits:[{name:'Large surface lure',effectiveness:10},{name:'Live baitfish',effectiveness:9},{name:'Large fly',effectiveness:8},{name:'Whole deadfish',effectiveness:7}],rigs:[{name:'Surface lure cast',description:'Large topwater lure worked near the surface where arapaima are breathing'},{name:'Live bait ledger',description:'Large live baitfish on heavy mono with strong circle hook'}],hookSizes:['6/0','8/0'],lineWeight:'80-100lb',legalSize:0,recordWeight:200,averageWeight:'50-120kg',averageLength:'150-250cm',tips:['Watch for the distinctive rolling breath \u2014 arapaima must surface for air and this reveals their location','Cast ahead of a surfacing fish \u2014 they move in a predictable direction after breathing','River boat expedition with local guide is the only way to access prime arapaima waters','Brazil requires a fishing licence and most arapaima are catch-and-release only'],difficulty:'expert',emoji:'\ud83d\udc1f',bestTimes:{timeOfDay:['Dawn (5am-8am)','Late afternoon (3pm-6pm)'],moonPhase:'Full moon periods when fish are most active at surface',season:'Dry season June-November when water levels drop and fish concentrate.',temperature:'Tropical water 26-30\xb0C ideal.',barometric:'Stable tropical conditions.',weather:'Clear, dry conditions. Arapaima are most visible on calm days.'},catchingTips:['Cruise the river at dawn watching for rolling arapaima \u2014 mark their location and circle back','Cast a large surface lure 5-10m ahead of a surfacing fish and retrieve steadily'],commonMistakes:['Casting directly on top of a surfacing fish \u2014 spooks them instantly','Using tackle that is too light \u2014 arapaima will straighten normal hooks'],proTips:['The Amazon lodge fishing operations in Brazil offer the best access. Weeks in advance booking required.']},{id:'giant_mekong_catfish',name:'Giant Mekong Catfish',commonName:'Mekong Catfish',latinName:'Pangasianodon gigas',type:'coarse',rarity:'mythic',rarityColor:'#EC4899',rarityDescription:'The world\'s largest freshwater fish by weight. Critically endangered \u2014 fewer than a few hundred remain in the wild.',spawnConditions:'Upper Mekong River during monsoon migration. Specialist fishing parks in Thailand.',catchRate:2,habitat:'Mekong River basin from Thailand to China. Specialist fishing parks near Chiang Rai, Thailand.',behaviour:'Vegetarian giant that feeds on algae and plant matter. Migrates upstream to spawn.',bestSeasons:['December-April (dry season Thailand)'],bestWeather:'Dry season when fishing parks operate. Stable, hot conditions.',baits:[{name:'Dough balls (rice flour)',effectiveness:10},{name:'Bread paste',effectiveness:9},{name:'Algae dough',effectiveness:8}],rigs:[{name:'Heavy ledger',description:'Strong running ledger on 80lb+ line with large circle hook and vegetarian bait'}],hookSizes:['6/0','8/0'],lineWeight:'80-120lb',legalSize:0,recordWeight:293,averageWeight:'100-200kg',averageLength:'200-300cm',tips:['Wild fishing for true Mekong Catfish is essentially impossible \u2014 specialist parks near Chiang Rai, Thailand offer the experience','Use vegetarian dough bait \u2014 this species does not eat fish or meat','Heavy specialist gear is mandatory \u2014 even a moderate specimen will test 80lb tackle'],difficulty:'expert',emoji:'\ud83d\udc1f',bestTimes:{timeOfDay:['Morning (6am-10am)','Evening (4pm-7pm)'],moonPhase:'Any \u2014 fishing park conditions apply',season:'Dry season October-April at Thailand specialist parks.',temperature:'Tropical 28-32\xb0C water.',barometric:'Stable tropical high pressure.',weather:'Dry, hot conditions. Avoid monsoon season.'},catchingTips:['Book a guided session at a specialist fishing park near Chiang Rai, Thailand','Use a large dough ball made from rice flour compressed firmly on a circle hook'],commonMistakes:['Using meat or fish-based bait \u2014 Mekong Catfish are vegetarian','Underestimating the power \u2014 even a guide may need to assist landing'],proTips:['Bungsamran Lake and IT Monster Lake near Bangkok also hold Mekong Catfish.','The world record of 293kg was caught in the wild in Thailand in 2005.']},{id:'giant_trevally',name:'Giant Trevally',commonName:'Giant Trevally',latinName:'Caranx ignobilis',type:'sea',rarity:'mythic',rarityColor:'#EC4899',rarityDescription:'Apex inshore saltwater predator. Charges at prey at extraordinary speed. The ultimate topwater target on remote Indo-Pacific atolls.',spawnConditions:'Remote Indo-Pacific atolls, coral reef passes and deep reef edges at dawn and dusk.',catchRate:4,habitat:'Indo-Pacific coral reefs, atolls, lagoon passes \u2014 Seychelles, Maldives, Christmas Island, Western Australia.',behaviour:'Highly aggressive apex predator that charges at speed from deep water. Known to attack seabirds. Incredibly powerful fighter.',bestSeasons:['Year-round in tropical zones','April-October at prime atolls'],bestWeather:'Calm, clear tropical mornings at dawn. Reef passes most productive.',baits:[{name:'Large topwater popper',effectiveness:10},{name:'Large stickbait',effectiveness:9},{name:'Live baitfish',effectiveness:9},{name:'Large jig',effectiveness:8}],rigs:[{name:'Heavy popping setup',description:'Heavy spinning rod 50-100lb braid, large popper worked aggressively'},{name:'Stickbait',description:'Slow-sinking stickbait worked with sharp rod twitches through reef passes'}],hookSizes:['3/0','4/0','5/0 (treble on lures)'],lineWeight:'50-100lb braid, 100lb fluorocarbon leader',legalSize:0,recordWeight:80,averageWeight:'10-40kg',averageLength:'80-160cm',tips:['Cast into reef passes at the start of the incoming tide \u2014 GT ambush prey in the current','Retrieve topwater lures aggressively \u2014 GT respond to frantic, noisy surface commotion','Never stop the lure if a GT is following \u2014 a pause means a missed fish'],difficulty:'expert',emoji:'\ud83d\udc20',bestTimes:{timeOfDay:['Dawn (first light)','Dusk','Incoming tide through reef passes'],tideState:'Incoming tide through reef passes and over coral flats',moonPhase:'Spring tides produce the most active hunting GT',season:'Year-round in tropics. Alphonse, Cosmoledo, and Astove atolls peak April-October.',temperature:'Sea temp 26-30\xb0C. Warm tropical waters year-round.',barometric:'Any stable tropical condition.',weather:'Calm mornings, clear water for sight fishing on the flats.'},catchingTips:['On flats, cast 10m ahead of a cruising GT and work the lure towards it aggressively','In reef passes, cast across the current and work the lure back with fast, violent rod sweeps'],commonMistakes:['Setting the drag too loose \u2014 GT run hard and fast and will give back line until they reach reef structure','Pausing lures when a GT is following \u2014 always maintain action until the fish commits'],proTips:['The Seychelles Outer Islands (Alphonse, Astove, Cosmoledo) are the world\'s best GT destination \u2014 book a year in advance']},{id:'blue_marlin',name:'Blue Marlin',commonName:'Blue Marlin',latinName:'Makaira nigricans',type:'sea',rarity:'mythic',rarityColor:'#EC4899',rarityDescription:'The ultimate offshore gamefish. Can exceed 500kg. Every serious big game angler dreams of a blue marlin grander.',spawnConditions:'Deep blue offshore water with temperature breaks, current edges, and bait concentrations.',catchRate:2,habitat:'Deep blue water worldwide \u2014 Atlantic, Pacific, Indian Oceans. Caribbean, Azores, Madeira, Baja California, Hawaii, Cairns.',behaviour:'Apex oceanic predator that hunts at speed near the surface. Uses its bill to slash through baitfish. Highly migratory.',bestSeasons:['Atlantic: June-November','Pacific: Year-round'],bestWeather:'Calm offshore conditions. Blue water with warm current edges and flying fish.',baits:[{name:'Rigged ballyhoo',effectiveness:10},{name:'Trolled skirted lure',effectiveness:9},{name:'Live skipjack tuna',effectiveness:10}],rigs:[{name:'Trolling spread',description:'6-8 baits and lures trolled at 7-9 knots in a spread pattern behind a sportfisher'},{name:'Stand-up heavy tackle',description:'130lb class tackle with roller guides for fighting a grander'}],hookSizes:['10/0','12/0','14/0'],lineWeight:'80-130lb',legalSize:0,recordWeight:636,averageWeight:'100-350kg',averageLength:'200-400cm',tips:['The Azores, Madeira, and Caribbean are the top Atlantic blue marlin destinations','A "grander" is a marlin over 1000lb (453kg) \u2014 the holy grail of big game fishing','Fully crewed charter boat is essential \u2014 blue marlin fishing is a team effort','Catch and release is strongly encouraged \u2014 marlin populations are under pressure'],difficulty:'expert',emoji:'\ud83d\udc2c',bestTimes:{timeOfDay:['Dawn through midday \u2014 peak marlin feeding'],moonPhase:'Full moon periods historically produce the biggest marlin',season:'Atlantic peaks August-October. Azores June-September. Pacific year-round.',temperature:'Sea temp 24-28\xb0C. Blue marlin prefer warm, clean blue water.',barometric:'Stable offshore conditions. Avoid tropical storms.',weather:'Calm, clear blue water days with good visibility.'},catchingTips:['Work the color change where blue offshore water meets greener inshore water \u2014 this is the feeding zone','Watch for birds diving and flying fish leaping \u2014 these indicate bait concentrations'],commonMistakes:['Poor hookset \u2014 marlin bills can tangle in lines. Captain directs when to strike hard','Not wearing a fighting harness \u2014 a large marlin fight can last hours'],proTips:['The Azores Islands in the mid-Atlantic are legendary for the largest Atlantic blue marlin. August-September peak.','Cairns, Australia produces black marlin to 600kg+ in October-November.']}]},816,[]);
