__d(function(g,r,i,a,m,e,d){"use strict";Object.defineProperty(e,'__esModule',{value:!0}),Object.defineProperty(e,"BAIT_CATEGORIES",{enumerable:!0,get:function(){return t}}),Object.defineProperty(e,"BAITS",{enumerable:!0,get:function(){return s}});const t=['Boilies','Pellets','Naturals','Lures','Flies','Deadbaits','Groundbait','Paste','Particle'],s=[{id:'boilies',name:'Boilies',emoji:'\ud83d\udd35',category:'Boilies',description:'Boilies are the most popular carp bait. Round, hard balls of mixed ingredients boiled to create a tough outer skin.',bestSpecies:['Carp','Bream','Tench'],seasons:['Spring','Summer','Autumn'],howToUse:'Hair-rig below a lead or inline lead setup. Cast to showing fish or known feeding areas.',rigRecommendations:['Hair Rig','Chod Rig','Pop-up Rig'],preparationTips:'Soak in boilie dip or liquid attractant overnight for extra attraction. Freeze unused boilies.',speciesEffectiveness:{Carp:10,Bream:6,Tench:5}},{id:'pellets',name:'Pellets',emoji:'\ud83d\udfe4',category:'Pellets',description:'Compressed fish meal pellets that break down slowly, releasing attractants. Ideal for carp, barbel and bream.',bestSpecies:['Carp','Barbel','Bream','Tench'],seasons:['Spring','Summer','Autumn'],howToUse:'On a hair rig, band, or method feeder. Micro pellets used as loose feed.',rigRecommendations:['Method Feeder','Hair Rig','Band Rig'],preparationTips:'Soak hard pellets for 30 mins to soften. Use micro pellets on a method feeder with dampened paste.',speciesEffectiveness:{Carp:9,Barbel:9,Bream:8,Tench:7}},{id:'corn',name:'Sweetcorn',emoji:'\ud83c\udf3d',category:'Particle',description:'Bright yellow and sweet-smelling, sweetcorn is a classic carp and tench bait that works year-round.',bestSpecies:['Carp','Tench','Bream','Chub'],seasons:['Spring','Summer','Autumn','Winter'],howToUse:'Single grain on a size 10-14 hook, or multiple grains on a hair rig.',rigRecommendations:['Hair Rig','Simple Hook Rig'],preparationTips:'Tin corn is ready to use. Add flavouring (tutti frutti or strawberry) for extra attraction.',speciesEffectiveness:{Carp:8,Tench:8,Bream:7,Chub:7,Roach:5}},{id:'luncheon-meat',name:'Luncheon Meat',emoji:'\ud83c\udf56',category:'Naturals',description:'A classic barbel and carp bait. Cheap, smelly and incredibly effective on rivers and stillwaters.',bestSpecies:['Barbel','Carp','Chub','Tench'],seasons:['Summer','Autumn'],howToUse:'Cut into cubes (1-2cm). Hair rig for carp, straight through the hook for barbel.',rigRecommendations:['Simple Hook Rig','Hair Rig'],preparationTips:'Fry lightly to firm it up \u2014 prevents falling off the hook. Add chilli powder for extra scent.',speciesEffectiveness:{Barbel:9,Carp:8,Chub:8,Tench:6}},{id:'maggots',name:'Maggots',emoji:'\ud83d\udc1b',category:'Naturals',description:'The most versatile coarse fishing bait. Works for almost every species in all seasons.',bestSpecies:['Roach','Perch','Bream','Dace','Chub','Tench'],seasons:['Spring','Summer','Autumn','Winter'],howToUse:'Two maggots on a size 14-18 hook through the blunt end. Use as loose feed to attract fish.',rigRecommendations:['Float Rig','Waggler Rig','Simple Hook Rig'],preparationTips:'Keep cool to prevent them turning into casters. Maize flour stops them sticking together.',speciesEffectiveness:{Roach:10,Perch:9,Dace:9,Bream:8,Chub:8,Tench:7}},{id:'worms',name:'Worms',emoji:'\ud83e\udeb1',category:'Naturals',description:'Lobworms and dendrobaenas are excellent natural baits, especially after rain.',bestSpecies:['Perch','Chub','Barbel','Eel','Tench','Bream'],seasons:['Spring','Summer','Autumn'],howToUse:'Thread half a lobworm onto a size 8-10 hook. Bunch of dendrobaenas for perch on size 10-12.',rigRecommendations:['Float Rig','Ledger Rig'],preparationTips:'Hook through the saddle (band) for best presentation. Nip the tail to release juices.',speciesEffectiveness:{Perch:10,Chub:9,Barbel:8,Eel:9,Tench:8,Bream:7}},{id:'bread',name:'Bread',emoji:'\ud83c\udf5e',category:'Naturals',description:'Cheap and effective. Bread punch, flake and crust all work for different species.',bestSpecies:['Roach','Chub','Carp','Bream'],seasons:['Autumn','Winter'],howToUse:'Punch from fresh white bread for small hooks. Pinch flake around a size 12-14 hook.',rigRecommendations:['Float Rig','Simple Hook Rig'],preparationTips:'Use day-old bread for firmer texture. Mashed bread with water makes an excellent groundbait.',speciesEffectiveness:{Roach:9,Chub:9,Carp:7,Bream:8}},{id:'spinners',name:'Spinners & Spoons',emoji:'\u2728',category:'Lures',description:'Metal lures that rotate or wobble to mimic small baitfish. Excellent for predators.',bestSpecies:['Pike','Perch','Chub','Zander'],seasons:['Spring','Autumn','Winter'],howToUse:'Cast and retrieve at varying speeds. Blade spinners for perch, larger spoons for pike.',rigRecommendations:['Wire Trace','Fluorocarbon Leader'],preparationTips:'Keep blades polished for maximum flash. Use a wire trace for pike to prevent bite-offs.',speciesEffectiveness:{Pike:8,Perch:9,Chub:7,Zander:7}},{id:'soft-plastics',name:'Soft Plastic Lures',emoji:'\ud83d\udc1f',category:'Lures',description:'Rubber/silicone lures including shads, worms and creatures. Natural-feeling in the water.',bestSpecies:['Pike','Perch','Zander','Chub'],seasons:['Spring','Summer','Autumn'],howToUse:'Jig head or drop-shot rig. Vary retrieve speed and depth to find active fish.',rigRecommendations:['Jig Head','Drop Shot','Carolina Rig'],preparationTips:'Match colour to water clarity: natural in clear, bright in coloured. Change plastics when scent fades.',speciesEffectiveness:{Perch:10,Zander:9,Pike:8,Chub:6}},{id:'dry-flies',name:'Dry Flies',emoji:'\ud83e\udeb0',category:'Flies',description:'Flies that float on the surface imitating emerging or adult insects.',bestSpecies:['Brown Trout','Rainbow Trout','Grayling'],seasons:['Spring','Summer'],howToUse:'Present upstream, allow to drift naturally. Mend line to avoid drag.',rigRecommendations:['Tippet to Leader','Dry Fly Rig'],preparationTips:'Apply floatant (Gink) before fishing. Match the hatch \u2014 observe what insects are flying.',speciesEffectiveness:{BrownTrout:10,RainbowTrout:9}},{id:'nymphs',name:'Nymphs',emoji:'\ud83e\udeb2',category:'Flies',description:'Subsurface fly patterns imitating aquatic insects. Often more effective than dry flies.',bestSpecies:['Brown Trout','Rainbow Trout'],seasons:['Spring','Summer','Autumn'],howToUse:'Czech nymphing, indicator nymphing or Euro nymphing techniques.',rigRecommendations:['Duo Rig','Tight Line Nymph'],preparationTips:'Add tungsten bead to get deeper. Fish the "drift zone" \u2014 seams between fast and slow water.',speciesEffectiveness:{BrownTrout:10,RainbowTrout:10}},{id:'mackerel-deadbait',name:'Mackerel Deadbait',emoji:'\ud83d\udc21',category:'Deadbaits',description:'Oily sea fish deadbait. Pike find the scent irresistible, especially in cold water.',bestSpecies:['Pike'],seasons:['Autumn','Winter'],howToUse:'Half mackerel on two size 8 treble hooks \u2014 one through tail, one through head. Static or drifted.',rigRecommendations:['Wire Trace','Float Rig'],preparationTips:'Inject with flavoured oil for extra scent trail. Freeze and thaw baits are fine to use.',speciesEffectiveness:{Pike:10}},{id:'hemp',name:'Hemp Seed',emoji:'\ud83c\udf31',category:'Particle',description:'Small, oily seeds that attract roach and barbel. One of the best loose feed baits.',bestSpecies:['Roach','Barbel','Chub','Bream'],seasons:['Summer','Autumn'],howToUse:'Mainly as loose feed to attract fish. Use single grain on tiny hook (18-20) for roach.',rigRecommendations:['Float Rig','Simple Hook Rig'],preparationTips:'Must be cooked (boiled 20-30 min) before use. Never use raw hemp \u2014 illegal in some venues.',speciesEffectiveness:{Roach:9,Barbel:9,Chub:8,Bream:7}},{id:'groundbait',name:'Groundbait',emoji:'\ud83d\udca7',category:'Groundbait',description:'Mixed base of breadcrumb, fishmeal and attractants. Forms a cloud of scent to attract fish.',bestSpecies:['Bream','Roach','Tench','Carp'],seasons:['Spring','Summer','Autumn'],howToUse:'Mix to soft balls, catapult or pot in at regular intervals. Feeder fishing uses dry groundbait packed loosely.',rigRecommendations:['Feeder Rig','Method Feeder'],preparationTips:'Mix consistently \u2014 walnut-sized balls that just hold together. Add liquid attractant for stronger scent.',speciesEffectiveness:{Bream:9,Roach:8,Tench:8,Carp:7}},{id:'tiger-nuts',name:'Tiger Nuts',emoji:'\ud83e\udd5c',category:'Particle',description:'Sweet, crunchy particle bait. One of the best carp baits especially in summer.',bestSpecies:['Carp'],seasons:['Summer','Autumn'],howToUse:'Hair rig with single or double tiger nut. Soak and boil overnight before use.',rigRecommendations:['Hair Rig','Chod Rig'],preparationTips:'Must be soaked 24 hrs then boiled 30 min \u2014 raw tiger nuts can harm fish. Add salt during soaking.',speciesEffectiveness:{Carp:9}},{id:'paste',name:'Paste',emoji:'\ud83d\udfe1',category:'Paste',description:'Soft, pliable bait wrapped around the hook. Releases constant scent in the water.',bestSpecies:['Carp','Barbel','Tench'],seasons:['Summer','Autumn'],howToUse:'Mould a walnut-sized ball around a size 6-8 hook. Cast and let it slowly break down.',rigRecommendations:['Simple Hook Rig'],preparationTips:'Make from crushed boilies and boiling water. Keep in damp cloth to prevent drying.',speciesEffectiveness:{Carp:8,Barbel:7,Tench:7}}]},836,[]);
