__d(function(g,r,i,a,m,e,d){"use strict";Object.defineProperty(e,'__esModule',{value:!0}),Object.defineProperty(e,"RIGS",{enumerable:!0,get:function(){return t}});const t=[{id:'running_lead',name:'Running Lead Rig',useCase:'General coarse fishing, carp fishing at range',targetSpecies:['Carp','Bream','Tench'],difficulty:'beginner',emoji:'\ud83c\udfa3',components:['Running lead 2-3oz','Lead clip','Tail rubber','Anti-tangle sleeve','Swivel','Hooklink (15-20cm)','Hook size 6-10'],steps:['Thread your mainline through the running lead or lead clip','Tie your mainline to a swivel using a grinner knot','Attach the anti-tangle sleeve to the swivel','Tie your hooklink (braid or fluorocarbon) to the other side of the swivel','Tie your chosen hook to the hooklink using a knotless knot','Attach your bait or hair rig to the hook','Check the lead can run freely \u2014 this is critical for self-hooking'],bestFor:['Silt bottoms','Carp fishing','Self-hooking presentation','Open water'],relatedKnots:['Grinner Knot','Knotless Knot','Palomar Knot'],description:'The running lead rig allows the line to run freely through the lead, so when a fish picks up the bait and moves off, it feels no resistance until the hook sets. A classic and highly effective rig.'},{id:'helicopter_rig',name:'Helicopter Rig',useCase:'Fishing over weed, silt, or soft bottom substrates',targetSpecies:['Carp','Bream'],difficulty:'intermediate',emoji:'\ud83d\ude81',components:['Helicopter rig setup (leadcore or tubing)','Inline or semi-fixed lead','Two bead stops','Swivel for hooklink attachment','Hooklink 10-20cm','Hook size 4-8'],steps:['Thread your mainline through the helicopter setup \u2014 top bead, hooklink swivel, bottom bead, then the lead','Tie the lead to the end of your mainline','Set the position of the beads to adjust hooklink height above the bottom','Tie your hooklink to the free-running swivel','For silt: set hooklink to sit 2-3cm above lakebed','For weed: extend the hooklink position to 10-15cm above bottom','Tie hook using knotless knot and add hair rig'],bestFor:['Silty lakes','Weed beds','Deep water','Long range'],relatedKnots:['Knotless Knot','Loop Knot'],description:'The helicopter rig keeps your hooklink rotating freely above the lakebed, making it perfect for fishing over soft silt or thick weed where other rigs would become buried.'},{id:'chod_rig',name:'Chod Rig',useCase:'Fishing over weed, chod (dead plant matter), and debris',targetSpecies:['Carp'],difficulty:'advanced',emoji:'\ud83c\udf3f',components:['Size 4-6 wide gape or chod hook','Stiff boom material (fluorocarbon 20-25lb)','20-25cm boom','Small ring swivel','Bead stops','Lead clip system'],steps:['Cut a 20-25cm length of stiff fluorocarbon for the boom','Create a small D-ring at one end using a ring swivel','Tie the hook using a knotless knot, leaving a 2-3cm hair','Blow-back rig the hook so it flips freely','Thread the boom through your lead system with free-sliding beads','Set the position so the hookbait sits 5-10cm above the debris','Pop-up boilies work best \u2014 use enough foam to balance the hook weight'],bestFor:['Chod layers','Weed beds','Unknown bottom','Pop-up baits'],relatedKnots:['Knotless Knot','Palomar Knot'],description:'The chod rig is a specialist carp rig designed to present a pop-up hookbait above any bottom debris. The stiff boom prevents tangles in even the most difficult conditions.'},{id:'zig_rig',name:'Zig Rig',useCase:'Targeting carp feeding at mid-water or near the surface',targetSpecies:['Carp'],difficulty:'intermediate',emoji:'\u2b06\ufe0f',components:['Size 8-10 wide gape hook','Mono hooklink (6-8lb)','Foam or Chum Mixer hookbait','Lead (2-3oz)','Adjustable zig kit or straight lead'],steps:['Measure the depth of the water at your chosen spot','Start with hooklink length at about 2/3 of the depth','Tie your chosen hook to the mono hooklink','Attach a small piece of yellow or black zig foam or a Chum Mixer','Tie hooklink to swivel on your lead system','Cast to your spot and let the hookbait float up to depth','Experiment with depth until fish are found \u2014 adjust hooklink in 1m increments'],bestFor:['Surface feeding carp','Hot weather','Clear water','Bright conditions'],relatedKnots:['Grinner Knot','Overhand Knot'],description:'The zig rig suspends a hookbait at any depth in the water column. When carp are not feeding on the bottom \u2014 especially in hot weather \u2014 this can be devastatingly effective.'},{id:'method_feeder',name:'Method Feeder Rig',useCase:'Attracting fish quickly with groundbait around the hookbait',targetSpecies:['Carp','Bream','Tench','Roach'],difficulty:'beginner',emoji:'\ud83c\udffa',components:['Method feeder (flat or cage)','Ready-tied or inline method mount','Short hooklink 5-8cm','Size 10-14 hook','Hair rig or directly tied bait'],steps:['Thread your mainline through the inline method feeder','Tie mainline to a small swivel using a grinner knot','Attach a short (5-8cm) hooklink to the swivel','Tie your hook using a knotless knot for hair-rigged bait','Mix your method mix groundbait to a stiff, sticky consistency','Mould groundbait around the feeder, encasing the hooklink','Embed your hookbait in the centre of the groundbait','Cast accurately and wait \u2014 bites are often instant'],bestFor:['Commercial fisheries','Bream','Carp','Beginner-friendly'],relatedKnots:['Knotless Knot','Grinner Knot'],description:'The method feeder rig is one of the most effective commercial fishery tactics. Groundbait mouded around the feeder creates a feeding frenzy, and the short hooklink means fish hook themselves.'},{id:'waggler',name:'Waggler Float Rig',useCase:'Float fishing still waters and slow-moving rivers',targetSpecies:['Roach','Rudd','Bream','Perch'],difficulty:'beginner',emoji:'\ud83c\udf8f',components:['Straight or insert waggler float','Float stops (two)','Split shot (various)','Size 14-18 hook','Mainline 3-5lb','Hooklength 2-3lb 30cm'],steps:['Thread mainline through the eye of the waggler','Lock the float with two float stops \u2014 one either side of the float eye','Add bulk shot 30cm above the hook to set depth','Add two small dropper shot between the bulk and hook','Tie a loop in the end of your mainline and attach hooklength by loop-to-loop','Tie hook to hooklength using a spade-end knot or tucked half-blood','Set the depth so hookbait just touches or drags the bottom','Cast slightly beyond your feed, draw the float back to the feeding zone'],bestFor:['Still waters','Canals','Slow rivers','Small fish'],relatedKnots:['Spade End Knot','Half-Blood Knot'],description:'The waggler is the most versatile float for still water fishing. Casting with an overhead throw, the float locked with shot at its base creates a stable, sensitive presentation.'},{id:'pole_rig',name:'Pole Float Rig',useCase:'Precise presentation at close range in canals and commercial lakes',targetSpecies:['Roach','Skimmer Bream','Carp','Tench'],difficulty:'intermediate',emoji:'\ud83c\udff9',components:['Pole float (0.1g-1g)','Hollow elastic (8-14)','Stonfo connector','Fine diameter mainline 0.1-0.18mm','Hooklength 0.08-0.14mm','Size 16-22 fine wire hook'],steps:['Thread elastic through the top two or three sections of the pole','Attach a Stonfo connector to the end of the elastic','Wind mainline around a winder, attaching to the connector with a figure-of-eight loop','Thread line through the float and lock with a float band','Attach bulk olivette shot 25-30cm from the hook','Add dropper shots in reducing size toward the hook','Tie hooklength to mainline using a four-turn water knot','Tie hook using a spade end knot \u2014 barbless hooks recommended'],bestFor:['Canals','Commercial fisheries','Precision fishing','Shallow water'],relatedKnots:['Four-Turn Water Knot','Spade End Knot'],description:'Pole fishing offers pinpoint accuracy and extreme sensitivity. The direct connection between pole and float removes line drag, making detection of the most delicate bites possible.'},{id:'float_rig',name:'River Float Rig',useCase:'Trotting a bait through flowing water',targetSpecies:['Roach','Dace','Chub','Grayling','Barbel'],difficulty:'beginner',emoji:'\ud83c\udf0a',components:['Avon or chubber float','Rubber float bands','Mainline 4-6lb','Shot pattern','Size 12-16 hook','Hooklength 3-4lb'],steps:['Attach float to mainline using two rubber float bands top and bottom','Set the float to slightly over depth so bait drags the river bed','Spread shot evenly along the hooklink to keep bait down in the flow','Cast upstream and allow the float to trot naturally with the current','Hold back slightly to make the bait swing away from the float enticingly','Mend the line to keep in contact with the float','Strike immediately on any dip or hesitation of the float'],bestFor:['Rivers','Streams','Chub','Trotting maggots or worms'],relatedKnots:['Half-Blood Knot','Spade End Knot'],description:'River trotting with a float is one of the most natural and satisfying ways to fish. The current carries your bait downstream to feeding fish, covering a long stretch of water.'},{id:'texas_rig',name:'Texas Rig',useCase:'Lure fishing in heavy cover and snaggy water',targetSpecies:['Perch','Pike','Zander'],difficulty:'intermediate',emoji:'\ud83e\udd20',components:['Bullet weight (7-21g)','Bead','Offset wide-gap hook size 2-4','Soft plastic lure (worm, creature bait)'],steps:['Thread the bullet weight onto the mainline or leader, pointed end first','Add a small bead to protect the knot from the weight','Tie the offset wide-gap hook using a Palomar knot','Thread the hook point through the nose of the soft plastic about 1cm','Slide the bait up the shank of the hook to the eye','Rotate the hook 180 degrees','Lay the bait against the hook and push the point just under the plastic skin (weedless)','The bait should hang straight without twisting'],bestFor:['Weedy water','Snags','Lure fishing','Perch'],relatedKnots:['Palomar Knot'],description:'Originally a bass fishing technique from America, the Texas rig is perfect for presenting soft plastics in UK waters where snags would otherwise claim your tackle.'},{id:'drop_shot',name:'Drop Shot Rig',useCase:'Vertical lure fishing for perch and zander',targetSpecies:['Perch','Zander','Bass'],difficulty:'beginner',emoji:'\u2b07\ufe0f',components:['Finesse rod','Braid mainline','Fluorocarbon leader 6-8lb','Dropshot hook size 4-8','Drop shot weight 7-14g','Finesse soft plastic 3-4"'],steps:['Tie a dropshot hook to the fluorocarbon using a Palomar knot, leaving a 30-60cm tag end','Attach the drop shot weight to the tag end of fluorocarbon','Thread the soft plastic through the nose and out the side \u2014 keep it horizontal','Lower the rig to the bottom so the weight rests on the bottom','The lure should sit 30-60cm above the bottom','Shake the rod tip gently to impart action while keeping weight on bottom','Strikes are often subtle \u2014 watch the line or use a sensitive rod tip'],bestFor:['Perch fishing','Clear water','Vertical jigging','Boat fishing'],relatedKnots:['Palomar Knot'],description:'The drop shot keeps your lure at a precise height above the bottom, letting you work it on the spot with tantalising shakes. A go-to technique for perch and zander in clear water.'},{id:'ledger',name:'Ledger Rig',useCase:'Bottom fishing in still water with quivertip or rod tip indication',targetSpecies:['Bream','Tench','Barbel','Chub'],difficulty:'beginner',emoji:'\u2693',components:['Bomb or feeder weight 1-2oz','Swivel','Anti-tangle sleeve','Hooklength 20-30cm','Size 12-16 hook'],steps:['Thread mainline through the bomb swivel or running feeder','Tie mainline to a swivel using a grinner knot','Attach the hooklength to the other side of the swivel','Tie the hook to the hooklength using a half-blood or knotless knot','Add bait \u2014 maggot, worm, or paste','Cast out and pull tight to the lead, placing rod on rests','Watch the quivertip for bites \u2014 a steady pull or series of knocks'],bestFor:['Still water fishing','Bream','Barbel','Feeder fishing'],relatedKnots:['Grinner Knot','Half-Blood Knot'],description:'The basic ledger rig is the most versatile bottom-fishing presentation. Simple, reliable and effective for a huge range of species across all types of water.'},{id:'paternoster',name:'Paternoster Rig',useCase:'Sea fishing from shore, presenting bait above a sinker',targetSpecies:['Cod','Bass','Flatfish','Whiting'],difficulty:'beginner',emoji:'\ud83c\udf0a',components:['30lb mono mainline','Flowing trace 15lb 50cm','Swivel connector','Bait clip (optional)','Size 1-2/0 hook','4-8oz lead'],steps:['Tie the sinker to the end of your mainline using a locked loop','Add a swivel 50cm above the sinker using a three-way swivel or blood loop','Tie a 50cm snood of 15lb mono to the swivel','Tie your chosen hook to the snood','For a two-hook rig, add a second snood 60cm above the first','Use a bait clip to hold the bait against the trace for longer casts','Bait up with lugworm, squid or crab and cast with a smooth overhead style'],bestFor:['Shore fishing','Cod','Whiting','Rough ground'],relatedKnots:['Grinner Knot','Blood Loop'],description:'The paternoster is the most common sea fishing rig in the UK. The hook snood sits above the lead, keeping bait off the rough sea bed and visible to passing fish.'},{id:'running_paternoster',name:'Running Paternoster',useCase:'Running line sea fishing for wary flatfish and bass',targetSpecies:['Flounder','Plaice','Bass','Ray'],difficulty:'intermediate',emoji:'\ud83d\udc0b',components:['Running boom or ring swivel','Mainline','50cm lead link','Flowing trace 24-36 inches','Size 1-2 hook'],steps:['Thread your mainline through a running boom or ring swivel','Tie a strong swivel below the boom as a stop','Attach a 50cm lead link to the bottom of the boom to hold the sinker','Tie a long flowing trace (24-36 inches) to the swivel','Attach hook to trace and bait with ragworm, lugworm or sandeel','The rig allows fish to take line without feeling the weight','Bites show as the line going slack or moving to the side'],bestFor:['Flatfish','Sandy beaches','Wary fish','Tidal estuaries'],relatedKnots:['Grinner Knot','Palomar Knot'],description:'The running paternoster allows a fish to pick up the bait and move off without feeling the weight. This makes it ideal for cautious flatfish on clean sandy beaches.'},{id:'fixed_paternoster',name:'Fixed Paternoster Rig',useCase:'Long-range sea fishing for distance casting competitions and cod',targetSpecies:['Cod','Whiting','Dogfish'],difficulty:'advanced',emoji:'\ud83c\udfaf',components:['Shockleader 60lb','Body of rig 30lb mono','Two hook snoods','Bait clips','Wishbone or T-bar clip','Size 2-4/0 hooks','6oz lead'],steps:['Tie a 60lb shockleader, 30 turns minimum onto the mainline','Create the rig body from 30lb stiff mono \u2014 body length should be 3ft','Tie in two snoods using blood loops, one at 12 inches, one at 24 inches from the lead','Attach bait clips at each snood junction for streamlined casting','Tie a three-way swivel to the bottom for the lead attachment','Clip baits (lugworm or squid) up to the bait clips for aerodynamic casting','Deliver a smooth, powerful pendulum or off-the-ground cast to maximise distance'],bestFor:['Distance casting','Beach fishing','Cod','Winter fishing'],relatedKnots:['Grinner Knot','Blood Loop','Leader Knot'],description:'The fixed paternoster with bait clips is the standard UK distance casting rig. Clipping baits up streamlines the rig for maximum distance \u2014 essential for beaches where fish are far offshore.'},{id:'live_bait',name:'Live Bait Rig',useCase:'Presenting a live fish as bait for large predators',targetSpecies:['Pike','Perch','Zander','Catfish'],difficulty:'advanced',emoji:'\ud83d\udc20',components:['50lb fluorocarbon or wire trace 30cm','Two size 6-8 treble hooks','Snap swivel','Pike float (optional)','Bait fish (roach, skimmer or rudd)'],steps:['Create or buy a ready-made wire trace with two snap-linked treble hooks','Set the hooks in a tandem arrangement \u2014 4-5cm apart for a 4-5 inch bait','Mount the baitfish by hooking one treble through both lips (or dorsal) and the second through the flank','Attach a pike float set to suspend bait at mid-depth or near bottom','Lower or cast gently to avoid harming the bait','Allow the baitfish to swim freely \u2014 any sudden movement of the float indicates interest','On take, give line briefly then strike to set both hooks'],bestFor:['Pike fishing','Stillwater predators','Big perch','Autumn/Winter'],relatedKnots:['Figure-Eight Knot for wire'],description:'Presenting a live baitfish is one of the most effective methods for pike and large predators. The natural movement of the bait triggers an instinctive attack response.'}]},886,[]);
